let chain = Chain::new()
  .add_link(Box::new(Link::new("sanitize", |ctx| {
    let input = ctx.get("input")
      .and_then(|v| v.as_str())
      .unwrap_or("")
      .trim().to_string();
    ctx.set("input", json!(input));
    ctx
  })))
  .add_link(Box::new(Link::new("process", |ctx| {
    ctx.set("result", json!("done"));
    ctx
  })));

let mut ctx = State::new();
ctx.set("input", json!("  hello  "));
let result = chain.execute(ctx);
println!("{:?}", result.get("result"));
